Here are pytest-style unit tests without special formatting:

from pytest import raises

from your_module import compose


def test_compose_happy_path():
    def add1(x): return x + 1
    def times2(x): return x * 2

    fn = compose(add1, times2)  # means add1(times2(x))
    assert fn(3) == 7  # times2(3)=6, add1(6)=7


def test_compose_single_function():
    def square(x): return x * x

    fn = compose(square)
    assert fn(4) == 16


def test_compose_no_functions():
    fn = compose()
    assert fn(10) == 10  # identity behavior


def test_compose_function_order():
    def to_str(x): return f"{x}!"
    def negate(x): return -x

    fn = compose(to_str, negate)
    assert fn(5) == "-5!"


def test_compose_with_non_numeric():
    def strip(x): return x.strip()
    def upper(x): return x.upper()

    fn = compose(strip, upper)
    assert fn("  hi ") == "HI"


def test_compose_error_in_function():
    def boom(x): raise ValueError("Bad input")
    fn = compose(boom)

    with raises(ValueError):
        fn("anything")


def test_compose_function_returns_invalid_input_for_next():
    def f1(x): return None
    def f2(x): return x + 1  # will error if x is None

    fn = compose(f1, f2)
    with raises(TypeError):
        fn(3)


def test_compose_functions_that_mutate():
    def append_a(lst):
        lst.append("a")
        return lst
    def append_b(lst):
        lst.append("b")
        return lst

    fn = compose(append_a, append_b)
    result = fn([])

    # Both should have been appended in order: append_b runs first
    assert result == ["b", "a"]
